void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	string sTemp;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "BlackTwister_capitan":			dialog.text = StringFromKey("BlackTwister_capitan_1");			link.l1 = StringFromKey("BlackTwister_capitan_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("BlackTwister_capitan_3");			link.l1 = StringFromKey("BlackTwister_capitan_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("BlackTwister_capitan_5");			link.l1 = StringFromKey("BlackTwister_capitan_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("BlackTwister_capitan_7");			link.l1 = StringFromKey("BlackTwister_capitan_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("BlackTwister_capitan_9");			link.l1 = StringFromKey("BlackTwister_capitan_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("BlackTwister_capitan_11");			link.l1 = StringFromKey("BlackTwister_capitan_12");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("BlackTwister_capitan_13");			link.l1 = StringFromKey("BlackTwister_capitan_14");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("BlackTwister_capitan_15");			link.l1 = StringFromKey("BlackTwister_capitan_16");			link.l1.go = "exit";			AddDialogExitQuest("FL2_s31");		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}